import time
from functools import wraps
def retry(times=3, delay=1):
    def decorator(f):
        @wraps(f)
        def wrapper(*a, **kw):
            for i in range(times):
                try: return f(*a, **kw)
                except Exception as e:
                    if i == times-1: raise
                    time.sleep(delay)
        return wrapper
    return decorator
