import json, sys, os
TODO_FILE = os.path.expanduser('~/.todo.json')
def load():
    if os.path.exists(TODO_FILE):
        with open(TODO_FILE) as f: return json.load(f)
    return []
def save(todos):
    with open(TODO_FILE, 'w') as f: json.dump(todos, f)
if len(sys.argv) < 2:
    print('Usage: todo add|list|done|rm <text|id>')
    sys.exit(1)
todos = load()
if sys.argv[1] == 'add':
    todos.append({'text': ' '.join(sys.argv[2:]), 'done': False})
    save(todos); print('Added')
elif sys.argv[1] == 'list':
    for i, t in enumerate(todos):
        print(f'{i}. {"[x]" if t["done"] else "[ ]"} {t["text"]}')
elif sys.argv[1] == 'done':
    todos[int(sys.argv[2])]['done'] = True; save(todos); print('Done')
elif sys.argv[1] == 'rm':
    del todos[int(sys.argv[2])]; save(todos); print('Removed')
