import time, os, hashlib
from watchdog.observers import Observer
from watchdog.events import FileSystemEventHandler
import logging
logging.basicConfig(filename='watch.log', level=logging.INFO)
class Handler(FileSystemEventHandler):
    def on_modified(self, e):
        logging.info(f'Modified: {e.src_path}')
    def on_created(self, e):
        logging.info(f'Created: {e.src_path}')
    def on_deleted(self, e):
        logging.info(f'Deleted: {e.src_path}')
observer = Observer()
observer.schedule(Handler(), path='/watch', recursive=True)
observer.start()
try:
    while True: time.sleep(1)
except KeyboardInterrupt: observer.stop()
observer.join()
